#raw
"""Self-contained orchestration shim inlined into the Galaxy tool XMLs.

The pipeline tools run in foreign container images (analyzer, data-assembler)
that intentionally know nothing about the NDIP workflow state. This shim is the
small bit of NDIP-schema logic the tool *wrapper* needs at runtime:

  - ``project-out STAGE STATE_JSON``
        print the shell-quoted CLI args for a stage, built from the state.
  - ``merge-in STAGE STATE_IN RESULT_JSON EXIT_CODE STATE_OUT [--output-prefix DIR]``
        fold a tool's neutral ndip-tool-result/1 manifest back into the state.
  - ``get STATE DOTTED.PATH``  — print a nested value (used by XML bash).
  - ``set-llm STATE PROVIDER MODEL BASE_URL OUT`` — fill blank
        ``inputs.operator.llm.*`` fields without overriding populated ones.

Galaxy injects this file into the tool container via a configfile element, so
the foreign image needs only ``python`` — not ``ndip_state``. It is **stdlib-only**
and a faithful bundle of ``src/ndip_state/{state,projection,canonicalize,adapters}.py``;
``tests/test_ndip_shim.py`` asserts it stays in agreement with those modules.

Do not edit by hand in a way that diverges from src/ndip_state — the parity
test will fail.
"""

import argparse
import hashlib
import json
import os
import shlex
import sys


SCHEMA_VERSION = "2"
_STAGES = ("reduction", "analysis", "assembly")
_STATUS_FROM_MANIFEST = {
    "ok": "ok",
    "dry-run": "ok",
    "skipped": "skipped",
    "failed": "failed",
    "needs-reprocessing": "failed",
}


# --------------------------------------------------------------------------
# state load / save  (mirrors src/ndip_state/state.py)
# --------------------------------------------------------------------------

def _empty_stage():
    return {"status": "pending", "params": {}, "artifacts": {}, "info": {}}


def empty_state():
    return {
        "schema_version": SCHEMA_VERSION,
        "workflow": {},
        "inputs": {"operator": {}, "derived": {}},
        "stages": {s: _empty_stage() for s in _STAGES},
        "errors": [],
    }


def load_state(path):
    if not path or not os.path.isfile(path):
        return empty_state()
    with open(path) as f:
        d = json.load(f)
    if not isinstance(d, dict):
        return empty_state()
    if str(d.get("schema_version")) != SCHEMA_VERSION:
        raise ValueError(
            "state document has schema_version=%r; expected %r"
            % (d.get("schema_version"), SCHEMA_VERSION)
        )
    return d


def save_state(state, path):
    with open(path, "w") as f:
        json.dump(state, f, indent=2)


# --------------------------------------------------------------------------
# merge_stage / record_error  (mirrors src/ndip_state/state.py)
# --------------------------------------------------------------------------

def record_error(state, stage, message, exit_code=None):
    state.setdefault("errors", []).append({
        "stage": stage, "message": message, "exit_code": exit_code,
    })
    return state


def _manifest_to_stage_status(manifest, exit_code):
    if exit_code not in (0, None):
        return "failed"
    return _STATUS_FROM_MANIFEST.get((manifest or {}).get("status"), "failed")


def _first_error_message(manifest):
    for m in (manifest or {}).get("messages") or []:
        if isinstance(m, dict) and m.get("level") == "error" and m.get("text"):
            return m["text"]
    return None


def merge_stage(state, stage, manifest, exit_code=0):
    manifest = manifest or {}
    block = state.setdefault("stages", {}).setdefault(stage, _empty_stage())
    block["status"] = _manifest_to_stage_status(manifest, exit_code)
    for key in ("params", "artifacts", "info"):
        incoming = manifest.get(key)
        if incoming:
            block.setdefault(key, {}).update(incoming)
    if block["status"] == "failed":
        msg = _first_error_message(manifest) or "%s failed" % stage
        record_error(state, stage, msg, manifest.get("exit_code", exit_code))
    return state


# --------------------------------------------------------------------------
# projection  (mirrors src/ndip_state/projection.py)
# --------------------------------------------------------------------------

POSITIONAL = "__positional__"


class ProjectionError(ValueError):
    pass


def _get(state, *keys):
    node = state
    for k in keys:
        if not isinstance(node, dict):
            return ""
        node = node.get(k)
    return node if node is not None else ""


def _outdir(state):
    return _get(state, "inputs", "operator", "output_directory")


def _rundir(state):
    out = _outdir(state)
    if not out:
        return ""
    run = _get(state, "workflow", "run")
    if run in ("", None):
        return out
    return os.path.join(out, str(run))


def _sub(state, name):
    run_dir = _rundir(state)
    return os.path.join(run_dir, name) if run_dir else ""


def _job_yaml(state):
    return (
        _get(state, "stages", "analysis", "artifacts", "job_yaml")
        or _get(state, "stages", "analysis", "params", "job_yaml")
    )


def _model_if_analysis_ok(state):
    if _get(state, "stages", "analysis", "status") == "ok":
        return _get(state, "stages", "analysis", "artifacts", "problem_json")
    return ""


def _ingest_dir(state):
    return (
        _get(state, "stages", "assembly", "artifacts", "ingest_dir")
        or _get(state, "stages", "assembly", "artifacts", "assembled_directory")
    )


def _seq_total(state):
    v = _get(state, "inputs", "operator", "sequence_total")
    return "" if v == "" else str(v)


STAGE_PROJECTIONS = {
    "reduction": [
        ("--event-file", lambda s: _get(s, "inputs", "derived", "nexus_file"), True),
        ("--template", lambda s: _get(s, "inputs", "operator", "template_file"), True),
        ("--output-dir", _outdir, True),
    ],
    "plan": [
        (POSITIONAL, lambda s: _get(s, "stages", "reduction", "artifacts", "partial_file"), True),
        (POSITIONAL, lambda s: _get(s, "inputs", "operator", "context_file"), True),
        ("--output-dir", lambda s: _sub(s, "plan"), True),
        ("--sequence-total", _seq_total, False),
        ("--llm-provider", lambda s: _get(s, "inputs", "operator", "llm", "provider"), False),
        ("--llm-model", lambda s: _get(s, "inputs", "operator", "llm", "model"), False),
        ("--llm-base-url", lambda s: _get(s, "inputs", "operator", "llm", "base_url"), False),
    ],
    "analyze": [
        (POSITIONAL, _job_yaml, True),
        ("--results-dir", lambda s: _sub(s, "results"), True),
        ("--reports-dir", lambda s: _sub(s, "reports"), True),
    ],
    "ingest": [
        ("-o", lambda s: _sub(s, "assembled"), True),
        ("--reduced", lambda s: _get(s, "stages", "reduction", "artifacts", "partial_file"), False),
        ("--nexus-file", lambda s: _get(s, "inputs", "derived", "nexus_file"), False),
        ("--model", _model_if_analysis_ok, False),
    ],
    "convert": [
        (POSITIONAL, _ingest_dir, True),
        ("--raw", lambda s: _get(s, "inputs", "derived", "nexus_file"), False),
        ("--reduced", lambda s: _get(s, "stages", "reduction", "artifacts", "partial_file"), False),
    ],
}


def project_out(stage, state):
    spec = STAGE_PROJECTIONS.get(stage)
    if spec is None:
        raise ProjectionError("unknown stage: %s" % stage)
    args = []
    for flag, getter, required in spec:
        value = str(getter(state) or "")
        if not value:
            if required:
                raise ProjectionError(
                    "stage %r: missing required value for %s"
                    % (stage, "positional arg" if flag == POSITIONAL else flag)
                )
            continue
        if flag == POSITIONAL:
            args.append(value)
        else:
            args.extend([flag, value])
    return args


def project_out_shell(stage, state):
    return " ".join(shlex.quote(a) for a in project_out(stage, state))


# --------------------------------------------------------------------------
# canonicalize  (mirrors src/ndip_state/canonicalize.py)
# --------------------------------------------------------------------------

def _prefix_map(canonical):
    if not canonical:
        return None
    resolved = os.path.realpath(canonical)
    if resolved == canonical:
        return None
    c_parts = canonical.split(os.sep)
    r_parts = resolved.split(os.sep)
    suffix = 0
    for i in range(1, min(len(c_parts), len(r_parts)) + 1):
        if c_parts[-i] == r_parts[-i]:
            suffix = i
        else:
            break
    if suffix == 0:
        return None
    c_prefix = os.sep.join(c_parts[:-suffix]) or os.sep
    r_prefix = os.sep.join(r_parts[:-suffix]) or os.sep
    if c_prefix == r_prefix:
        return None
    return r_prefix.rstrip(os.sep) + os.sep, c_prefix.rstrip(os.sep) + os.sep


def canonicalize_paths(obj, canonical):
    mapping = _prefix_map(canonical)
    if mapping is None:
        return obj
    needle, replacement = mapping

    def rewrite(node):
        if isinstance(node, dict):
            return {k: rewrite(v) for k, v in node.items()}
        if isinstance(node, list):
            return [rewrite(v) for v in node]
        if isinstance(node, str) and node.startswith(needle):
            return replacement + node[len(needle):]
        return node

    return rewrite(obj)


# --------------------------------------------------------------------------
# merge-in / adapters  (mirrors src/ndip_state/adapters.py)
# --------------------------------------------------------------------------

_TARGET = {
    "reduction": "reduction",
    "plan": "analysis",
    "analyze": "analysis",
    "ingest": "assembly",
    "convert": "assembly",
}


def _sha256(path):
    try:
        h = hashlib.sha256()
        with open(path, "rb") as f:
            for chunk in iter(lambda: f.read(65536), b""):
                h.update(chunk)
        return h.hexdigest()
    except OSError:
        return ""


def _derived_params(stage, state):
    out = {}
    if stage == "reduction":
        template = _get(state, "inputs", "operator", "template_file")
        if template:
            out["template_file"] = template
            sha = _sha256(template)
            if sha:
                out["template_sha256"] = sha
    elif stage in ("ingest", "convert"):
        nexus = _get(state, "inputs", "derived", "nexus_file")
        reduced = _get(state, "stages", "reduction", "artifacts", "partial_file")
        if nexus:
            out["nexus_input"] = nexus
        if reduced:
            out["reduced_input"] = reduced
        if _get(state, "stages", "analysis", "status") == "ok":
            model = _get(state, "stages", "analysis", "artifacts", "problem_json")
            if model:
                out["model_input"] = model
    return out


def merge_in(stage, state, manifest, exit_code=0, output_prefix=None):
    if stage not in _TARGET:
        raise ValueError("unknown stage: %s" % stage)
    manifest = dict(manifest or {})
    derived = _derived_params(stage, state)
    if derived:
        blended = dict(derived)
        blended.update(manifest.get("params") or {})
        manifest["params"] = blended
    merge_stage(state, _TARGET[stage], manifest, exit_code)
    if output_prefix:
        canonical = canonicalize_paths(state, output_prefix)
        if canonical is not state:
            state.clear()
            state.update(canonical)
    return state


# --------------------------------------------------------------------------
# CLI
# --------------------------------------------------------------------------

def _cmd_project_out(args):
    state = load_state(args.state)
    sys.stdout.write(project_out_shell(args.stage, state))


def _cmd_merge_in(args):
    state = load_state(args.state_in)
    manifest = {}
    if args.result and os.path.isfile(args.result):
        with open(args.result) as f:
            loaded = json.load(f)
        if isinstance(loaded, dict):
            manifest = loaded
    # Default the canonicalization prefix to the operator output directory.
    prefix = args.output_prefix or _outdir(state) or None
    merge_in(args.stage, state, manifest, args.exit_code, output_prefix=prefix)
    save_state(state, args.state_out)


def _cmd_get(args):
    """Print a dotted-path value from the state, for tool bash."""
    node = load_state(args.state)
    for key in args.path.split("."):
        node = node.get(key) if isinstance(node, dict) else None
        if node is None:
            break
    sys.stdout.write("" if node is None else str(node))


def _cmd_rundir(args):
    """Print the per-run output subdirectory (output_directory joined with run).

    The tool XMLs build their plan/results/reports/assembled dirs off this so
    they match what ``project-out`` passes to the foreign CLIs. Falls back to
    the bare output directory when no run number is present.
    """
    sys.stdout.write(_rundir(load_state(args.state)))


def _cmd_set_llm(args):
    """Fill blank inputs.operator.llm.{provider,model,base_url} from arguments.

    Values already present in the state win; the args only fill blanks.
    """
    state = load_state(args.state)
    llm = state.setdefault("inputs", {}).setdefault("operator", {}).setdefault("llm", {})
    for value, key in ((args.provider, "provider"), (args.model, "model"), (args.base_url, "base_url")):
        if value and not llm.get(key):
            llm[key] = value
    save_state(state, args.out)


def main(argv=None):
    parser = argparse.ArgumentParser(prog="ndip-shim")
    sub = parser.add_subparsers(dest="cmd", required=True)
    stages = ["reduction", "plan", "analyze", "ingest", "convert"]

    p = sub.add_parser("project-out")
    p.add_argument("stage", choices=stages)
    p.add_argument("state")
    p.set_defaults(func=_cmd_project_out)

    p = sub.add_parser("merge-in")
    p.add_argument("stage", choices=stages)
    p.add_argument("state_in")
    p.add_argument("result")
    p.add_argument("exit_code", type=int)
    p.add_argument("state_out")
    p.add_argument("--output-prefix", default=None)
    p.set_defaults(func=_cmd_merge_in)

    p = sub.add_parser("get")
    p.add_argument("state")
    p.add_argument("path")
    p.set_defaults(func=_cmd_get)

    p = sub.add_parser("rundir")
    p.add_argument("state")
    p.set_defaults(func=_cmd_rundir)

    p = sub.add_parser("set-llm")
    p.add_argument("state")
    p.add_argument("provider")
    p.add_argument("model")
    p.add_argument("base_url")
    p.add_argument("out")
    p.set_defaults(func=_cmd_set_llm)

    args = parser.parse_args(argv)
    args.func(args)


if __name__ == "__main__":
    main()
#end raw
